/// main.rs
///
/// Neo CLI entry point.
///
/// Parses command-line arguments and dispatches to the appropriate
/// command implementation in the cli/ module.
///
/// Usage:
///   neo init                          # full scan, generate neo.md
///   neo init --agent claude           # also write CLAUDE.md instructions
///   neo update src/auth.ts src/api.ts # incremental update for changed files
///   neo validate                      # check neo.md is in sync

use clap::{Parser, Subcommand};
use std::path::PathBuf;

// Declare all modules — Rust requires explicit module declarations
mod types;
mod core;
mod parser;
mod ai;
mod agent;
mod cli;

// Re-export lib modules for library consumers
// (When this crate is used as a library, not just a binary)
pub use types::*;

/// Neo — AI-native codebase map for coding agents
///
/// Neo generates a compact neo.md file that coding agents read
/// instead of grepping your codebase. Significant token savings.
#[derive(Parser)]
#[command(name = "neo")]
#[command(version = "0.1.0")]
#[command(about = "AI-native codebase map for coding agents")]
#[command(long_about = None)]
struct Cli {
    /// Project root directory (defaults to current directory)
    #[arg(long, default_value = ".")]
    root: PathBuf,

    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Scan codebase and generate neo.md from scratch
    ///
    /// Run this once when setting up Neo for a project.
    /// This is the expensive operation — it calls AI for summaries.
    /// After init, use `neo update` for incremental changes.
    Init {
        /// Which agent instruction files to generate
        /// Options: claude, all
        /// Default: all
        #[arg(long, default_value = "all")]
        agent: String,
    },

    /// Update neo.md for specific changed files
    ///
    /// Called by the coding agent after making file changes.
    /// Much faster than `neo init` — only processes changed files.
    ///
    /// Example: neo update src/auth/token.ts src/api/user.ts
    Update {
        /// List of relative file paths that changed
        #[arg(required = true)]
        files: Vec<String>,
    },

    /// Validate that neo.md is in sync with the codebase
    ///
    /// Used in CI/CD pipelines to catch stale Neo before merging.
    /// Exits with code 1 if neo.md is out of sync.
    Validate,
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    let cli = Cli::parse();

    // Resolve project root to absolute path
    let project_root = cli.root.canonicalize().unwrap_or_else(|_| {
        std::env::current_dir().expect("Could not determine current directory")
    });

    // Dispatch to appropriate command
    match cli.command {
        Commands::Init { agent } => {
            cli::init::run(project_root, agent).await?;
        }
        Commands::Update { files } => {
            cli::update::run(project_root, files).await?;
        }
        Commands::Validate => {
            cli::validate::run(project_root)?;
        }
    }

    Ok(())
}

